import time
_counts = {}
def rate_limit(max_per_min=60):
    def decorator(handler):
        def wrapper(req):
            key = req.remote_addr
            now = time.time()
            window = _counts.get(key, (0, now))
            if now - window[1] > 60:
                window = (0, now)
            if window[0] >= max_per_min:
                return {'error': 'rate limited'}, 429
            _counts[key] = (window[0] + 1, window[1])
            return handler(req)
        return wrapper
    return decorator
